function Button<
    RootComponent extends React.ElementType = 'button',
>(
    inProps: ButtonProps<RootComponent>,
    ref: React.ForwardedRef<HTMLButtonElement | HTMLAnchorElement>
) {
    const props = useThemeProps({ props: inProps, name: PREFIX });
    const {
        alignIcon = 'left',
        children,
        className,
        disabled,
        label,
        color = 'primary',
        size = 'small',
        to: locationDescriptor,
        ...rest
    } = props;

    const translate = useTranslate();
    let translatedLabel = label;
    if (typeof label === 'string') {
        translatedLabel = translate(label, {
            _: label,
        });
    }
    const linkParams = getLinkParams(locationDescriptor);

    const isXSmall = useMediaQuery((theme: Theme) =>
        theme.breakpoints.down('sm')
    );

    return isXSmall ? (
        label && !disabled ? (
            <Tooltip title={translatedLabel}>
                <IconButton
                    ref={ref as React.Ref<HTMLButtonElement>}
                    // If users provide a ReactNode as label, its their responsibility to also provide an aria-label should they need it
                    aria-label={
                        typeof translatedLabel === 'string'
                            ? translatedLabel
                            : undefined
                    }
                    className={className}
                    color={color}
                    size="large"
                    {...linkParams}
                    {...rest}
                >
                    {children}
                </IconButton>
            </Tooltip>
        ) : (
            <IconButton
                ref={ref as React.Ref<HTMLButtonElement>}
                className={className}
                color={color}
                disabled={disabled}
                size="large"
                {...linkParams}
                {...rest}
            >
                {children}
            </IconButton>
        )
    ) : (
        <StyledButton
            ref={ref as React.Ref<HTMLButtonElement>}
            className={className}
            color={color}
            size={size}
            // If users provide a ReactNode as label, its their responsibility to also provide an aria-label should they need it
            aria-label={
                typeof translatedLabel === 'string'
                    ? translatedLabel
                    : undefined
            }
            disabled={disabled}
            startIcon={alignIcon === 'left' && children ? children : undefined}
            endIcon={alignIcon === 'right' && children ? children : undefined}
            {...linkParams}
            {...rest}
        >
            {translatedLabel}
        </StyledButton>
    );
}

export function NextAppProviderApp(props: AppProviderProps) {
  const pathname = usePathname();
  const searchParams = useSearchParams();
  const { push, replace } = useRouter();

  const navigate = React.useCallback<Navigate>(
    (url, { history = 'auto' } = {}) => {
      if (history === 'auto' || history === 'push') {
        return push(String(url));
      }
      if (history === 'replace') {
        return replace(String(url));
      }
      throw new Error(`Invalid history option: ${history}`);
    },
    [push, replace],
  );

  const routerImpl = React.useMemo<Router>(
    () => ({
      pathname,
      searchParams,
      navigate,
      Link,
    }),
    [pathname, navigate, searchParams],
  );

  return <AppProvider router={routerImpl} {...props} />;
}

