export const TabbedShowLayout = (inProps: TabbedShowLayoutProps) => {
    const props = useThemeProps({
        props: inProps,
        name: PREFIX,
    });
    const {
        children,
        className,
        spacing,
        divider,
        syncWithLocation = true,
        tabs = DefaultTabs,
        value,
        ...rest
    } = props;
    const { Route, Routes, Outlet } = useRouterProvider();
    const record = useRecordContext(props);
    const nonNullChildren = Children.toArray(children).filter(
        child => child !== null
    ) as ReactElement<{
        context?: string;
        spacing?: ResponsiveStyleValue<number | string>;
        divider?: ReactNode;
    }>[];
    const [tabValue, setTabValue] = useState(0);

    const handleTabChange = (event: ChangeEvent<{}>, value: any): void => {
        if (!syncWithLocation) {
            setTabValue(value);
        }
    };

    if (!record) {
        return null;
    }

    const renderTabHeaders = () =>
        cloneElement(
            tabs,
            {
                onChange: handleTabChange,
                syncWithLocation,
                value: tabValue,
            },
            nonNullChildren
        );

    return (
        <OptionalRecordContextProvider value={props.record}>
            <Root className={className} {...sanitizeRestProps(rest)}>
                {syncWithLocation ? (
                    <Routes>
                        <Route
                            path="/*"
                            element={
                                <>
                                    {renderTabHeaders()}
                                    <Divider />
                                    <div
                                        className={
                                            TabbedShowLayoutClasses.content
                                        }
                                    >
                                        <Outlet />
                                    </div>
                                </>
                            }
                        >
                            {Children.map(nonNullChildren, (tab, index) =>
                                isValidElement(tab) ? (
                                    <Route
                                        path={getShowLayoutTabFullPath(
                                            tab,
                                            index
                                        )}
                                        element={cloneElement(tab, {
                                            context: 'content',
                                            spacing,
                                            divider,
                                        })}
                                    />
                                ) : null
                            )}
                        </Route>
                    </Routes>
                ) : (
                    <>
                        {renderTabHeaders()}
                        <Divider />
                        <div className={TabbedShowLayoutClasses.content}>
                            {Children.map(nonNullChildren, (tab, index) => {
                                if (
                                    !isValidElement(tab) ||
                                    tabValue !== index
                                ) {
                                    return null;
                                }
                                return cloneElement(tab, {
                                    context: 'content',
                                    spacing,
                                    divider,
                                });
                            })}
                        </div>
                    </>
                )}
            </Root>
        </OptionalRecordContextProvider>
    );
}

