const Navigate = ({ to, replace, state }: RouterNavigateProps) => {
    const basename = useBasename();
    const router = useRouter();
    const currentLocation = useTanStackLocation();

    // Handle both string and object forms of `to`
    let resolvedPath: string;

    if (typeof to === 'string') {
        resolvedPath = to;
    } else {
        // If no pathname provided, use current pathname to stay on current page
        resolvedPath = to.pathname ?? currentLocation.pathname;

        // Append search and hash directly to the path to preserve the raw
        // query string format. TanStack Router's search prop uses JSON
        // serialization which is incompatible with standard URL query strings.
        if (to.search) {
            resolvedPath += to.search.startsWith('?')
                ? to.search
                : `?${to.search}`;
        }
        if (to.hash) {
            resolvedPath += to.hash.startsWith('#') ? to.hash : `#${to.hash}`;
        }

        // Merge state from object with state prop (prop takes precedence)
        state = state ?? to.state;
    }

    // Prepend basename to the path (like react-router does)
    // Only prepend if path doesn't already start with basename
    if (basename && resolvedPath.startsWith('/')) {
        if (
            !resolvedPath.startsWith(basename + '/') &&
            resolvedPath !== basename
        ) {
            resolvedPath = `${basename}${resolvedPath}`;
        }
    }

    // Use TanStack Router's navigate function
    const previousPathRef = React.useRef<string | null>(null);
    React.useLayoutEffect(() => {
        if (previousPathRef.current !== resolvedPath) {
            router.navigate({
                to: resolvedPath,
                state,
                replace,
            });
            previousPathRef.current = resolvedPath;
        }
    }, [router, resolvedPath, replace, state]);

    return null;
}

export const RichTextInput = (props: RichTextInputProps) => {
    const {
        className,
        defaultValue = '',
        disabled = false,
        editorOptions = DefaultEditorOptions,
        fullWidth = true,
        helperText,
        label,
        readOnly = false,
        source,
        sx,
        toolbar,
    } = props;

    const resource = useResourceContext(props);
    const {
        id,
        field,
        isRequired,
        fieldState,
        formState: { isSubmitted },
    } = useInput({ ...props, source, defaultValue });

    const editor = useEditor(
        {
            ...editorOptions,
            editable: !disabled && !readOnly,
            content: field.value,
            editorProps: {
                ...editorOptions?.editorProps,
                attributes: {
                    ...editorOptions?.editorProps?.attributes,
                    id,
                },
            },
        },
        [disabled, editorOptions, readOnly, id]
    );

    const { error, invalid, isTouched } = fieldState;

    useEffect(() => {
        if (!editor) return;

        const { from, to } = editor.state.selection;

        editor.commands.setContent(field.value, false, {
            preserveWhitespace: true,
        });
        editor.commands.setTextSelection({ from, to });
    }, [editor, field.value]);

    useEffect(() => {
        if (!editor) {
            return;
        }

        const handleEditorUpdate = () => {
            if (editor.isEmpty) {
                field.onChange('');
                field.onBlur();
                return;
            }

            const html = editor.getHTML();
            field.onChange(html);
            field.onBlur();
        };

        editor.on('update', handleEditorUpdate);
        editor.on('blur', field.onBlur);
        return () => {
            editor.off('update', handleEditorUpdate);
            editor.off('blur', field.onBlur);
        };
    }, [editor, field]);

    return (
        <Root
            className={clsx(
                'ra-input',
                `ra-input-${source}`,
                className,
                fullWidth ? 'fullWidth' : ''
            )}
            sx={sx}
        >
            <Labeled
                isRequired={isRequired}
                label={label}
                id={`${id}-label`}
                color={fieldState?.invalid ? 'error' : undefined}
                source={source}
                resource={resource}
                fullWidth={fullWidth}
            >
                <RichTextInputContent
                    editor={editor}
                    error={error}
                    helperText={helperText}
                    id={id}
                    isTouched={isTouched}
                    isSubmitted={isSubmitted}
                    invalid={invalid}
                    toolbar={toolbar || <RichTextInputToolbar />}
                />
            </Labeled>
        </Root>
    );
}

