function Crud<D extends DataModel>(props: CrudProps<D>) {
  const {
    dataSource,
    rootPath,
    initialPageSize,
    defaultValues,
    dataSourceCache,
    pageTitles,
    slots,
    slotProps,
  } = props;

  const listPath = rootPath;
  const showPath = `${rootPath}/:id`;
  const createPath = `${rootPath}/new`;
  const editPath = `${rootPath}/:id/edit`;

  const routerContext = React.useContext(RouterContext);

  const handleRowClick = React.useCallback(
    (id: string | number) => {
      routerContext?.navigate(`${rootPath}/${String(id)}`);
    },
    [rootPath, routerContext],
  );

  const handleCreateClick = React.useCallback(() => {
    routerContext?.navigate(createPath);
  }, [createPath, routerContext]);

  const handleEditClick = React.useCallback(
    (id: string | number) => {
      routerContext?.navigate(`${rootPath}/${String(id)}/edit`);
    },
    [rootPath, routerContext],
  );

  const handleCreate = React.useCallback(() => {
    routerContext?.navigate(listPath);
  }, [listPath, routerContext]);

  const handleEdit = React.useCallback(() => {
    routerContext?.navigate(listPath);
  }, [listPath, routerContext]);

  const handleDelete = React.useCallback(() => {
    routerContext?.navigate(listPath);
  }, [listPath, routerContext]);

  const renderedRoute = React.useMemo(() => {
    const pathname = routerContext?.pathname ?? '';

    if (match(listPath)(pathname)) {
      return (
        <List<D>
          initialPageSize={initialPageSize}
          onRowClick={handleRowClick}
          onCreateClick={handleCreateClick}
          onEditClick={handleEditClick}
          pageTitle={pageTitles?.list}
          slots={{
            ...(slots?.pageContainer
              ? {
                  pageContainer: slots?.pageContainer,
                }
              : {}),
            ...slots?.list,
          }}
          slotProps={{
            ...(slotProps?.pageContainer
              ? {
                  pageContainer: slotProps?.pageContainer,
                }
              : {}),
            ...slotProps?.list,
          }}
        />
      );
    }
    if (match(createPath)(pathname)) {
      return (
        <Create<D>
          initialValues={defaultValues}
          onSubmitSuccess={handleCreate}
          resetOnSubmit={false}
          pageTitle={pageTitles?.create}
          slots={{
            ...(slots?.form
              ? {
                  form: slots?.form,
                }
              : {}),
            ...(slots?.pageContainer
              ? {
                  pageContainer: slots?.pageContainer,
                }
              : {}),
          }}
          slotProps={{
            ...(slotProps?.form
              ? {
                  form: slotProps?.form,
                }
              : {}),
            ...(slotProps?.pageContainer
              ? {
                  pageContainer: slotProps?.pageContainer,
                }
              : {}),
          }}
        />
      );
    }
    const showMatch = match<{ id: DataModelId }>(showPath)(pathname);
    if (showMatch) {
      const resourceId = showMatch.params.id;
      invariant(resourceId, 'No resource ID present in URL.');
      return (
        <Show<D>
          id={resourceId}
          onEditClick={handleEditClick}
          onDelete={handleDelete}
          pageTitle={pageTitles?.show}
          slots={{
            ...(slots?.pageContainer
              ? {
                  pageContainer: slots?.pageContainer,
                }
              : {}),
          }}
          slotProps={{
            ...(slotProps?.pageContainer
              ? {
                  pageContainer: slotProps?.pageContainer,
                }
              : {}),
          }}
        />
      );
    }
    const editMatch = match<{ id: DataModelId }>(editPath)(pathname);
    if (editMatch) {
      const resourceId = editMatch.params.id;
      invariant(resourceId, 'No resource ID present in URL.');
      return (
        <Edit<D>
          id={resourceId}
          onSubmitSuccess={handleEdit}
          pageTitle={pageTitles?.edit}
          slots={{
            ...(slots?.form
              ? {
                  form: slots?.form,
                }
              : {}),
            ...(slots?.pageContainer
              ? {
                  pageContainer: slots?.pageContainer,
                }
              : {}),
          }}
          slotProps={{
            ...(slotProps?.form
              ? {
                  form: slotProps?.form,
                }
              : {}),
            ...(slotProps?.pageContainer
              ? {
                  pageContainer: slotProps?.pageContainer,
                }
              : {}),
          }}
        />
      );
    }
    return null;
  }, [
    createPath,
    defaultValues,
    editPath,
    handleCreate,
    handleCreateClick,
    handleDelete,
    handleEdit,
    handleEditClick,
    handleRowClick,
    initialPageSize,
    listPath,
    pageTitles,
    routerContext?.pathname,
    showPath,
    slotProps,
    slots,
  ]);

  return (
    <CrudProvider<D> dataSource={dataSource} dataSourceCache={dataSourceCache}>
      {renderedRoute}
    </CrudProvider>
  );
}

export const ThemeProvider = ({ children }: ThemeProviderProps) => {
    const { lightTheme, darkTheme, defaultTheme } = useThemesContext();

    const prefersDarkMode = useMediaQuery('(prefers-color-scheme: dark)', {
        noSsr: true,
    });
    const [mode] = useTheme(
        defaultTheme || (prefersDarkMode && darkTheme ? 'dark' : 'light')
    );

    const themeValue = useMemo(() => {
        try {
            return createTheme(mode === 'dark' ? darkTheme : lightTheme);
        } catch (e) {
            console.warn('Failed to reuse custom theme from store', e);
            return createTheme();
        }
    }, [mode, lightTheme, darkTheme]);

    return (
        <MuiThemeProvider theme={themeValue}>
            {/* Had to cast here because Provider only accepts ReactNode but we might have a render function */}
            {children as ReactNode}
        </MuiThemeProvider>
    );
}

