  );
  const field = <TextField onFocus={fieldHandler} />;

  return null;
}

export const removeTags = (input: string) => {
    if (!input) {
        return '';
    }

    let output = '';
    let isInsideTag = false;

    for (const character of input) {
        if (character === '<') {
            isInsideTag = true;
            continue;
        }

        if (character === '>') {
            if (isInsideTag) {
                isInsideTag = false;
                continue;
            }
        }

        if (!isInsideTag) {
            output += character;
        }
    }

    return output;
}

