export const Authenticated = (props: AuthenticatedProps) => {
    const { authParams, loading = null, children } = props;

    // this hook will redirect to login if the user is not authenticated
    const { isPending, isError } = useAuthenticated({ params: authParams });

    if (isPending || isError) {
        return loading;
    }

    return <>{children}</>;
}

function AccountPreview(props: AccountPreviewProps) {
  const { slots, variant = 'condensed', slotProps, open, handleClick, sx } = props;
  const session = React.useContext(SessionContext);
  const globalLocaleText = useLocaleText();
  const accountLocaleText = React.useContext(AccountLocaleContext);
  const localeText = { ...globalLocaleText, ...accountLocaleText };

  if (!session || !session.user) {
    return null;
  }

  const avatarContent = slots?.avatar ? (
    <slots.avatar />
  ) : (
    <Avatar
      src={session.user?.image || ''}
      alt={session.user?.name || session.user?.email || ''}
      sx={{ height: variant === 'expanded' ? 48 : 32, width: variant === 'expanded' ? 48 : 32 }}
      {...slotProps?.avatar}
    />
