import React from 'react';
import { Dialog, DialogTitle, DialogContent, DialogActions, Button } from '@mui/material';

/** Confirmation dialog with cancel and confirm buttons */

completion:
interface ConfirmDialogProps { open: boolean; title?: string; content?: React.ReactNode; onConfirm: () => void; onClose: () => void; }

function ConfirmDialog(props: ConfirmDialogProps) {
  const { open, title, content, onConfirm, onClose } = props;

  const handleConfirm = () => {
    onClose();
    onConfirm();
  };

  return (
    <Dialog
      open={open}
      onClose={onClose}
      aria-labelledby="alert-dialog-title"
      aria-describedby="alert-dialog-description"
    >
      <DialogTitle id="alert-dialog-title">
        {title ?? 'Confirm'}
      </DialogTitle>
      <DialogContent id="alert-dialog-description">
        {content}
      </DialogContent>
      <DialogActions>
        <Button onClick={onClose} variant="outlined">Cancel</Button>
        <Button onClick={handleConfirm} variant="contained" color="error">Confirm</Button>
      </DialogActions>
    </Dialog>
  );
}

